import axios from 'axios';

const API_URL = 'http://localhost:8080/ResidentialPro'; // Replace with your actual API URL

// Create a reusable Axios instance
const apiClient = axios.create({
  baseURL: API_URL,
  headers: {
    'Content-Type': 'application/json',
  },
});

export default {
  login(email, password) {
    return apiClient.post('/login?email='+email+'&password='+password);
  },


  getLotes() {
    return apiClient.get('/lotes');
  },

  getLote(id) {
    return apiClient.get('/lotes/'+id);
  },

  createLote(userData) {
    return apiClient.post('/lotes', userData);
  }
};
